    instructions = puzzle_input.strip()
    
    current_floor = 0
    first_basement_position = None
    
    # Iterate through the instructions tracking both index and character
    for position, char in enumerate(instructions, start=1):
        if char == '(':
            current_floor += 1
        elif char == ')':
            current_floor -= 1
            
